def _domain_findings(capability: Improve1Capability, payload: dict[str, Any]) -> tuple[str, ...]:
    findings: list[str] = []
    n = capability.feature_number
    if n == 1 and (payload.get("identity_confidence", 0) < 0.8 or payload.get("age_verification_status") != "verified" or payload.get("reviewer_evidence") in (None, "")):
        findings.append("patron enrollment requires confidence, age verification, and reviewer evidence")
    if n == 2 and (payload.get("self_excluded") or payload.get("barred") or payload.get("floor_access_allowed") is not True):
        findings.append("patron restrictions block floor access and session creation")
    if n == 3 and (payload.get("close_checklist") != "complete" or not payload.get("supervisor_assignment")):
        findings.append("table close requires reconciliation checklist and supervisor signoff")
    if n == 4 and (payload.get("supervisor_confirmation") is not True or not payload.get("dual_control_evidence")):
        findings.append("table inventory movement requires dual-control evidence")
    if n == 5 and (payload.get("jurisdiction_approval_state") != "approved" or payload.get("activation_allowed") is not True):
        findings.append("slot conversion cannot activate without jurisdiction approval")
    if n == 6 and (not payload.get("meter_snapshot") or payload.get("fault_evidence_complete") is not True or payload.get("reopen_allowed") is not True):
        findings.append("slot recovery requires meter snapshot and resolved fault evidence")
    if n == 9 and (payload.get("external_points_mutation_blocked") is not True or payload.get("campaign_ledger_owned") is True):
        findings.append("slot loyalty evidence cannot own external points or campaign ledgers")
    if n == 10 and (payload.get("journal_complete") is not True or payload.get("document_packet_status") != "complete"):
        findings.append("cage transaction journal requires verification and document packet")
    if n == 11 and (payload.get("close_allowed") is not True or not payload.get("meter_snapshot") or not payload.get("witness_evidence")):
        findings.append("jackpot cannot close without meter snapshot and witness evidence")
    if n == 12 and (payload.get("custody_chain_complete") is not True or payload.get("seal_mismatch_opened") is True):
        findings.append("drop custody chain is incomplete or has a seal mismatch")
    if n == 14 and (payload.get("cross_team_tasks_complete") is not True or payload.get("closure_allowed") is not True):
        findings.append("variance investigation cannot close without documented disposition")
    if n == 16 and (payload.get("play_session_blocked") is not True or payload.get("original_evidence_preserved") is not True):
        findings.append("self-exclusion must block play and preserve original evidence")
    if n == 22 and payload.get("media_storage_owned") is True:
        findings.append("surveillance review boundary cannot own video storage")
    if n == 26 and payload.get("closed_history_mutation_blocked") is not True:
        findings.append("policy propagation cannot mutate closed history")
    if n == 28 and (payload.get("double_payout_prevented") is not True or payload.get("double_session_prevented") is not True):
        findings.append("idempotent floor ingestion must prevent duplicate payouts and sessions")
    if n == 35 and (not payload.get("source_citations") or payload.get("inference_labeled") is not True):
        findings.append("shift briefing agent requires citations and labeled inference")
    if n == 38 and (payload.get("command_preview") is not True or payload.get("permission_check") is not True or payload.get("mutation_allowed") is True):
        findings.append("governed agent mutation requires preview, permission check, and no direct mutation")
    if n == 40 and (payload.get("foreign_reference_blocked") is not True or payload.get("finance_table_mutation_blocked") is not True or payload.get("loyalty_balance_owned") is True):
        findings.append("external boundary contract blocks foreign table ownership and mutations")
    if n == 44 and (payload.get("proof_verified") is not True or payload.get("altered_order_detected") is True or payload.get("payload_digest_valid") is not True):
        findings.append("cryptographic proof chain failed verification")
    if n == 45 and not all(payload.get(field) is True for field in ("jackpot_flow_tests", "count_custody_tests", "exclusion_enforcement", "workbench_persona_evidence", "agent_guardrails", "boundary_checks", "floor_lane_status", "cage_lane_status", "compliance_lane_status", "responsible_gaming_lane_status")):
        findings.append("floor readiness release evidence pack is incomplete")
    if n == 46 and payload.get("live_mutation_blocked") is not True:
        findings.append("peak-night simulation must not mutate live records")
    if n == 47 and payload.get("queue_leakage_blocked") is not True:
        findings.append("multi-property isolation must block queue leakage")
    if n == 48 and (payload.get("training_status") != "current" or payload.get("certification_recency") != "current" or payload.get("authority_valid") is not True):
        findings.append("sensitive action requires current training, certification, and authority")
    if n == 49 and (payload.get("deterministic_replay") is not True or payload.get("duplicate_settlement_prevented") is not True):
        findings.append("offline replay must be deterministic and prevent duplicate settlement")
    if n == 50 and not all(payload.get(field) is True for field in ("player_profile_seeded", "table_game_seeded", "slot_machine_seeded", "wager_session_seeded", "payout_seeded", "rg_case_seeded", "compliance_seeded", "apis_exercised", "events_emitted", "workbench_queues_driven", "assistant_summary_generated", "control_assertions_run", "release_documents_updated")):
        findings.append("end-to-end casino release rehearsal is incomplete")
    if payload.get("stream_engine_picker_visible"):
        findings.append("ordinary PBCs must not expose stream-engine pickers")
    return tuple(findings)


def evaluate_casino_control(capability: Improve1Capability | str | int, payload: dict[str, Any] | None = None) -> dict[str, Any]:
    resolved = _resolve(capability)
    if resolved is None: return {"ok": False, "reason": "unknown_capability", "side_effects": ()}
    spec = CONTROL_SPECS[resolved.feature_number]
    candidate = sample_payload_for(resolved); candidate.update(dict(payload or {}))
    missing_fields = tuple(field for field in spec["fields"] if field not in _EMPTY_ALLOWED_FIELDS and candidate.get(field) in (None, "", (), []))
    foreign_tables = tuple(table for table in spec["tables"] if table not in CASINO_CONTROL_OWNED_TABLES)
    undeclared_dependencies = tuple(dependency for dependency in spec["dependencies"] if dependency not in CASINO_CONTROL_DECLARED_DEPENDENCIES)
    findings = _domain_findings(resolved, candidate)
    evidence = {"evidence_id": _digest((PBC_KEY, resolved.feature_number, tuple(sorted(candidate))))[:20], "owned_tables": spec["tables"], "required_fields": spec["fields"], "ui_surface": spec["ui"], "service_api": spec["route"], "test": "tests/test_domain_behavior.py", "event_contract": EVENT_CONTRACT, "required_event_topic": CASINO_CONTROL_REQUIRED_EVENT_TOPIC, "allowed_database_backends": CASINO_CONTROL_ALLOWED_DATABASE_BACKENDS, "declared_dependencies": spec["dependencies"], "side_effects": ()}
    ok = not missing_fields and not foreign_tables and not undeclared_dependencies and not findings
    return {"ok": ok, "pbc": PBC_KEY, "feature_number": resolved.feature_number, "slug": resolved.slug, "title": resolved.title, "capability": resolved.as_traceability_row(), "payload": candidate, "evidence": evidence, "missing_fields": missing_fields, "foreign_tables": foreign_tables, "undeclared_dependencies": undeclared_dependencies, "findings": findings, "side_effects": ()}


def improve1_casino_control_contract() -> dict[str, Any]:
    evaluations = tuple(evaluate_casino_control(capability) for capability in CASINO_CONTROL_CAPABILITIES)
    blocking = tuple(item for item in evaluations if not item["ok"])
    return {"ok": not blocking, "pbc": PBC_KEY, "format": "appgen.gaming-casino-operations-improve1-control.v1", "capability_count": len(evaluations), "capabilities": evaluations, "owned_tables": CASINO_CONTROL_OWNED_TABLES, "declared_dependencies": CASINO_CONTROL_DECLARED_DEPENDENCIES, "allowed_database_backends": CASINO_CONTROL_ALLOWED_DATABASE_BACKENDS, "event_contract": EVENT_CONTRACT, "required_event_topic": CASINO_CONTROL_REQUIRED_EVENT_TOPIC, "stream_engine_picker_visible": False, "blocking_gaps": blocking, "side_effects": ()}


CASINO_CONTROL_FUNCTIONS = {capability.slug: (lambda payload=None, slug=capability.slug: evaluate_casino_control(slug, payload)) for capability in CASINO_CONTROL_CAPABILITIES}
